import React, { useState, useEffect } from 'react';
import axios from 'axios';
import '../styles/jobs.css';

const Jobs = () => {
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [typeFilter, setTypeFilter] = useState('All');
  const [applyingId, setApplyingId] = useState(null);
  const [appliedIds, setAppliedIds] = useState(new Set());
  const [selectedJob, setSelectedJob] = useState(null);
  const [toast, setToast] = useState(null);

  useEffect(() => {
    fetchJobs();
    fetchMyApplications();
  }, []);

  const fetchJobs = async () => {
    setLoading(true);
    try {
      const res = await axios.get('/api/jobs');
      setJobs(res.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const fetchMyApplications = async () => {
    try {
      const res = await axios.get('/api/applications/user');
      const ids = new Set(res.data.map(a => a.job?._id || a.job));
      setAppliedIds(ids);
    } catch (err) {
      // not logged in or no apps yet
    }
  };

  const handleApply = async (jobId) => {
    setApplyingId(jobId);
    try {
      await axios.post('/api/applications/apply', { jobId });
      setAppliedIds(prev => new Set([...prev, jobId]));
      showToast('✅ Application submitted successfully!', 'success');
    } catch (err) {
      showToast(err.response?.data?.message || 'Failed to apply. Please try again.', 'error');
    } finally {
      setApplyingId(null);
    }
  };

  const showToast = (message, type) => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3500);
  };

  const filtered = jobs.filter(j => {
    const matchType = typeFilter === 'All' || j.type === typeFilter;
    const matchSearch =
      j.title.toLowerCase().includes(search.toLowerCase()) ||
      j.companyName.toLowerCase().includes(search.toLowerCase()) ||
      j.location.toLowerCase().includes(search.toLowerCase());
    return matchType && matchSearch;
  });

  const jobCount = jobs.filter(j => j.type === 'Job').length;
  const internCount = jobs.filter(j => j.type === 'Internship').length;

  return (
    <div className="jobs-page page-content">
      {/* Toast */}
      {toast && (
        <div className={`toast toast-${toast.type}`}>{toast.message}</div>
      )}

      {/* Header */}
      <div className="jobs-header">
        <div className="container">
          <h1 className="jobs-title">Browse Opportunities</h1>
          <p className="jobs-subtitle">{jobs.length} listings available — find the one that fits you</p>

          {/* Search */}
          <div className="jobs-search-wrap">
            <span className="jobs-search-icon">🔍</span>
            <input
              type="text"
              placeholder="Search by title, company, or location..."
              value={search}
              onChange={e => setSearch(e.target.value)}
              className="jobs-search-input"
            />
            {search && (
              <button className="jobs-search-clear" onClick={() => setSearch('')}>✕</button>
            )}
          </div>

          {/* Filter Tabs */}
          <div className="jobs-filter-tabs">
            {[
              { label: 'All', count: jobs.length },
              { label: 'Job', count: jobCount },
              { label: 'Internship', count: internCount },
            ].map(tab => (
              <button
                key={tab.label}
                className={`jobs-tab ${typeFilter === tab.label ? 'active' : ''}`}
                onClick={() => setTypeFilter(tab.label)}
              >
                {tab.label} <span className="tab-count">{tab.count}</span>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Jobs Grid */}
      <div className="container jobs-grid-wrap">
        {loading ? (
          <div className="jobs-grid">
            {[1,2,3,4,5,6].map(i => (
              <div key={i} className="job-card-skeleton" />
            ))}
          </div>
        ) : filtered.length === 0 ? (
          <div className="jobs-empty">
            <div>🔍</div>
            <h3>No results found</h3>
            <p>{search ? `No listings match "${search}"` : 'No listings available right now.'}</p>
            {search && <button className="btn-primary" onClick={() => { setSearch(''); setTypeFilter('All'); }}>Clear Filters</button>}
          </div>
        ) : (
          <div className="jobs-grid">
            {filtered.map(job => {
              const applied = appliedIds.has(job._id);
              return (
                <div key={job._id} className="job-card" onClick={() => setSelectedJob(job)}>
                  <div className="job-card-top">
                    <div className="job-company-avatar">{job.companyName.charAt(0)}</div>
                    <span className={`badge ${job.type === 'Internship' ? 'badge-internship' : 'badge-job'}`}>
                      {job.type}
                    </span>
                  </div>
                  <h3 className="job-title">{job.title}</h3>
                  <p className="job-company">{job.companyName}</p>
                  <div className="job-meta">
                    <span>📍 {job.location}</span>
                    {job.salary && <span>💰 {job.salary}</span>}
                  </div>
                  {job.requirements?.length > 0 && (
                    <div className="job-skills">
                      {job.requirements.slice(0, 3).map(r => (
                        <span key={r} className="job-skill">{r}</span>
                      ))}
                      {job.requirements.length > 3 && (
                        <span className="job-skill more">+{job.requirements.length - 3}</span>
                      )}
                    </div>
                  )}
                  <div className="job-card-footer">
                    <span className="job-date">{new Date(job.createdAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' })}</span>
                    <button
                      className={`btn-apply ${applied ? 'applied' : ''}`}
                      disabled={applied || applyingId === job._id}
                      onClick={e => { e.stopPropagation(); !applied && handleApply(job._id); }}
                    >
                      {applyingId === job._id ? <span className="spinner" /> : applied ? '✓ Applied' : 'Apply Now'}
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Job Detail Modal */}
      {selectedJob && (
        <div className="job-modal-overlay" onClick={e => e.target === e.currentTarget && setSelectedJob(null)}>
          <div className="job-modal">
            <div className="job-modal-header">
              <div className="job-modal-company">
                <div className="job-company-avatar large">{selectedJob.companyName.charAt(0)}</div>
                <div>
                  <h2>{selectedJob.title}</h2>
                  <p>{selectedJob.companyName}</p>
                </div>
              </div>
              <button className="job-modal-close" onClick={() => setSelectedJob(null)}>✕</button>
            </div>

            <div className="job-modal-body">
              <div className="job-modal-meta">
                <span>📍 {selectedJob.location}</span>
                <span className={`badge ${selectedJob.type === 'Internship' ? 'badge-internship' : 'badge-job'}`}>{selectedJob.type}</span>
                {selectedJob.salary && <span>💰 {selectedJob.salary}</span>}
                <span>📅 {new Date(selectedJob.createdAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })}</span>
              </div>

              <div className="job-modal-section">
                <h3>About the Role</h3>
                <p>{selectedJob.description}</p>
              </div>

              {selectedJob.requirements?.length > 0 && (
                <div className="job-modal-section">
                  <h3>Requirements</h3>
                  <div className="job-modal-skills">
                    {selectedJob.requirements.map(r => (
                      <span key={r} className="job-skill">{r}</span>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="job-modal-footer">
              <button className="btn-outline" onClick={() => setSelectedJob(null)}>Close</button>
              <button
                className={`btn-apply large ${appliedIds.has(selectedJob._id) ? 'applied' : ''}`}
                disabled={appliedIds.has(selectedJob._id) || applyingId === selectedJob._id}
                onClick={() => !appliedIds.has(selectedJob._id) && handleApply(selectedJob._id)}
              >
                {applyingId === selectedJob._id ? <span className="spinner" /> : appliedIds.has(selectedJob._id) ? '✓ Applied' : 'Apply Now →'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Jobs;
